#!/bin/bash

# 禅道API配置
TOKEN="cf2da27b8b734b419352d844bc451a14"
PRODUCT_ID=1

# 测试用例数据 - 关联到对应的需求story
declare -A CASES=(
  ["TC-LOGIN-001|1|5|正常邀请码登录流程|用户打开登录页面|输入有效的邀请码|输入正确的验证码|点击登录按钮|登录成功，跳转到用户首页，显示用户手机号绑定信息"]="LOGIN"
  ["TC-LOGIN-002|1|5|邀请码已过期|输入已过期的邀请码|输入正确的验证码|点击登录按钮|登录失败，提示'邀请码已过期，请联系管理员'"]="LOGIN"
  ["TC-LOGIN-003|1|5|邀请码已被使用|输入已被使用的邀请码|输入正确的验证码|点击登录按钮|登录失败，提示'邀请码已被使用'"]="LOGIN"
  ["TC-LOGIN-004|1|5|邀请码格式错误|输入格式错误的邀请码|输入正确的验证码|点击登录按钮|登录失败，提示'邀请码格式不正确'"]="LOGIN"
  ["TC-LOGIN-005|1|5|验证码错误|输入有效的邀请码|输入错误的验证码|点击登录按钮|登录失败，提示'验证码错误'"]="LOGIN"
  ["TC-LOGIN-006|1|5|验证码为空|输入有效的邀请码|不输入验证码|点击登录按钮|登录失败，提示'请输入验证码'"]="LOGIN"
  ["TC-LOGIN-007|1|5|邀请码为空|不输入邀请码|输入验证码|点击登录按钮|登录失败，提示'请输入邀请码'"]="LOGIN"
  ["TC-LOGIN-008|1|5|邀请码和手机号绑定验证|用户使用邀请码首次登录|系统要求输入手机号进行绑定|输入手机号|完成绑定"]="LOGIN"
  ["TC-APPLY-001|1|6|正常申请流程|填写姓名、手机号、身份证号、地区、推荐人、补充说明|输入正确的验证码|勾选'首次申请'标记|点击提交按钮|申请提交成功，显示'申请已提交，请等待审核'"]="APPLY"
  ["TC-APPLY-002|1|6|姓名必填校验|不填写姓名|填写其他必填项|点击提交|提交失败，提示'姓名不能为空'"]="APPLY"
  ["TC-APPLY-003|1|6|手机号格式校验|填写格式错误的手机号|填写其他必填项|点击提交|提交失败，提示'手机号格式不正确'"]="APPLY"
  ["TC-APPLY-004|1|6|身份证号格式校验|填写格式错误的身份证号|填写其他必填项|点击提交|提交失败，提示'身份证号格式不正确'"]="APPLY"
  ["TC-APPLY-005|1|6|地区必填校验|不填写地区|填写其他必填项|点击提交|提交失败，提示'请选择地区'"]="APPLY"
  ["TC-APPLY-006|1|6|验证码必填校验|填写所有必填项|不输入验证码|点击提交|提交失败，提示'请输入验证码'"]="APPLY"
  ["TC-APPLY-007|1|6|重复申请检测|用户再次进入申请页面|尝试提交新的申请| |提示'您已有待审核的申请，请等待审核结果后再提交'"]="APPLY"
  ["TC-APPLY-008|1|6|非首次申请场景|系统显示'非首次申请'标记|重新填写申请信息|提交申请|申请提交成功，系统记录为重新申请"]="APPLY"
  ["TC-APPLY-009|1|6|申请信息修改|填写部分信息|点击'保存草稿'|关闭页面|重新进入申请页面|系统显示之前保存的草稿信息"]="APPLY"
  ["TC-APPLY-010|1|6|地区联动选择|选择省份|验证市区下拉框显示对应城市列表| | |地区省份选择后，城市列表正确加载"]="APPLY"
)

# 创建第一个用例验证API
echo "测试用例创建..."

# 循环创建用例
count=0
for line in "${CASES[@]}"; do
  IFS='|' read -r tc_id pri story title step1 step2 step3 step4 expect <<< "$line"
  
  # 构建steps数组
  steps="[{\"desc\":\"$step1\",\"expect\":\"$expect\"}"
  if [ -n "$step2" ]; then
    steps="$steps,{\"desc\":\"$step2\",\"expect\":\"$expect\"}"
  fi
  if [ -n "$step3" ]; then
    steps="$steps,{\"desc\":\"$step3\",\"expect\":\"$expect\"}"
  fi
  if [ -n "$step4" ]; then
    steps="$steps,{\"desc\":\"$step4\",\"expect\":\"$expect\"}"
  fi
  steps="$steps]"
  
  response=$(curl -s -X POST "http://192.168.0.28:9980/api.php/v1/products/$PRODUCT_ID/testcases" \
    -H "Content-Type: application/json" \
    -H "Token: $TOKEN" \
    -d "{
      \"title\": \"【$tc_id】$title\",
      \"pri\": $pri,
      \"type\": \"feature\",
      \"story\": $story,
      \"steps\": $steps
    }")
  
  id=$(echo "$response" | python3 -c "import sys,json; print(json.load(sys.stdin).get('id',''))" 2>/dev/null)
  if [ -n "$id" ]; then
    echo "✓ 创建成功: $tc_id (ID: $id)"
    ((count++))
  else
    echo "✗ 创建失败: $tc_id"
    echo "  Response: $response"
  fi
done

echo ""
echo "总计成功创建: $count 个测试用例"
